import React, { useState } from 'react';

const Contact = () => {
  const [form, setForm] = useState({ name: '', email: '', message: '' });
  const [errors, setErrors] = useState({});
  const [submitted, setSubmitted] = useState(false);

  const validate = () => {
    const e = {};
    if (!form.name.trim()) e.name = 'Name is required.';
    if (!form.email.trim()) e.email = 'Email is required.';
    else if (!/\S+@\S+\.\S+/.test(form.email)) e.email = 'Enter a valid email.';
    if (!form.message.trim()) e.message = 'Message cannot be empty.';
    return e;
  };

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
    setErrors({ ...errors, [e.target.name]: '' });
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    const errs = validate();
    if (Object.keys(errs).length > 0) { setErrors(errs); return; }
    setSubmitted(true);
  };

  return (
    <footer id="Contact" className="text-center mt-12 pt-6 pb-8 px-4" style={{ background: '#f8f9fa' }}>
      <h5 className="italic text-gray-500 pt-1 mb-4" style={{ fontFamily: "'Orbitron', sans-serif" }}>My Links</h5>

      <div id="social-links" className="flex justify-center items-center gap-5 mt-2 mb-8">
        <a href="https://github.com/amd-16" target="_blank" rel="noreferrer" className="transition-transform duration-300 hover:scale-110 inline-block">
          <img src="/images/github-logo.png" alt="GitHub" width="50" height="50" />
        </a>
        <a href="https://www.facebook.com/alihakim.dimacaling15" target="_blank" rel="noreferrer" className="transition-transform duration-300 hover:scale-110 inline-block">
          <img src="/images/facebook-logo.png" alt="Facebook" width="50" height="50" />
        </a>
        <a href="https://mail.google.com/mail/" target="_blank" rel="noreferrer" className="transition-transform duration-300 hover:scale-110 inline-block">
          <img src="/images/gmail-logo.png" alt="Gmail" width="50" height="50" />
        </a>
      </div>

      <div className="max-w-md mx-auto text-left">
        <h5 className="text-gray-700 font-bold mb-4 text-center text-sm">Send a Message</h5>
        {submitted ? (
          <p className="text-green-600 text-center font-semibold">Thanks, {form.name}! Your message has been sent.</p>
        ) : (
          <form onSubmit={handleSubmit} className="flex flex-col gap-3">
            <div>
              <input type="text" name="name" placeholder="Your name" value={form.name} onChange={handleChange} className="w-full border border-gray-300 rounded px-3 py-2 text-sm text-gray-800" />
              {errors.name && <p className="text-red-500 text-xs mt-1">{errors.name}</p>}
            </div>
            <div>
              <input type="text" name="email" placeholder="Your email" value={form.email} onChange={handleChange} className="w-full border border-gray-300 rounded px-3 py-2 text-sm text-gray-800" />
              {errors.email && <p className="text-red-500 text-xs mt-1">{errors.email}</p>}
            </div>
            <div>
              <textarea name="message" placeholder="Your message" value={form.message} onChange={handleChange} rows={4} className="w-full border border-gray-300 rounded px-3 py-2 text-sm resize-none text-gray-800" />
              {errors.message && <p className="text-red-500 text-xs mt-1">{errors.message}</p>}
            </div>
            <button type="submit" className="py-2 rounded text-white font-semibold transition hover:opacity-90" style={{ background: '#335765' }}>Send</button>
          </form>
        )}
      </div>
    </footer>
  );
};

export default Contact;
